const fullText = $input.first().json.data
  || $input.first().json.body || '';

// Strip XML/XBRL and HTML tags
const cleaned = fullText
  .replace(/<[^>]*>/g, ' ')
  .replace(/\s+/g, ' ')
  .replace(/"/g, "'")
  .replace(/\\/g, '')
  .replace(/[\x00-\x1F\x7F]/g, '')
  .trim();

// Take first ~40k chars to stay safe on token limits
const truncated = cleaned.substring(0, 40000);

return [{
  json: {
    ...$input.first().json,
    filing_text: truncated
  }
}];

return [{
  json: {
    content: [{
      text: JSON.stringify({
        summary: `${$json.company_name} filed a ${$json.form_type} on ${$json.filing_date}. [STUB] Pipeline validation data.`,
        key_risks: 'Regulatory environment changes; supply chain disruption risk (stub)',
        financial_highlights: 'Revenue: $X.XB; Operating margin: XX% (stub)',
        contracts_mentioned: 'Contract award mentioned; Boeing 787 program reference (stub)',
        workforce_changes: 'Headcount reduction planned in Q4 (stub)',
        sentiment: 'neutral',
        llm_model: 'stub-test'
      })
    }]
  }
}];

const response = $input.first().json;
const content = response.content[0].text;
let analysis;
try {
  const cleaned = content
    .replace(/```json|```/g, '')
    .trim();
  analysis = JSON.parse(cleaned);
} catch (e) {
  analysis = {
    summary: 'Parse error - raw response stored',
    raw_response: content,
    sentiment: 'neutral',
    confidence_score: 0
  };
}
return [{ json: analysis }];

const data = $input.first().json;
const company = {
  company_id: $('Get Companies').first().json.company_id,
  company_name: $('Get Companies').first().json.company_name,
  ticker_symbol: $('Get Companies').first().json.ticker_symbol,
  cik_number: $('Get Companies').first().json.cik_number
};
const recent = data.filings?.recent || data.recentFilings || {};
const forms = recent.form || [];
const dates = recent.filingDate || [];
const accessions = recent.accessionNumber || [];
const primaryDocs = recent.primaryDocument || [];
const descriptions = recent.primaryDocDescription || [];
const targetForms = ['10-K','10-Q','8-K','DEF 14A','S-1','20-F'];
const yesterday = new Date();
yesterday.setDate(yesterday.getDate() - 30);
const cutoff = yesterday.toISOString().split('T')[0];
const filings = [];
for (let i = 0; i < forms.length; i++) {
  if (targetForms.includes(forms[i]) && dates[i] >= cutoff) {
    const accClean = accessions[i].replace(/-/g, '');
    filings.push({
      ...company,
      form_type: forms[i],
      filing_date: dates[i],
      accession_number: accessions[i],
      primary_document: primaryDocs[i],
      description: descriptions[i] || '',
      filing_url: `https://www.sec.gov/Archives/edgar/data/`
        + `${company.cik_number}/${accClean}/${primaryDocs[i]}`
    });
  }
}
if (filings.length === 0) return [];
return filings.map(f => ({ json: f }));

const items = $input.all();

if (items.length === 0) {
  return [{
    json: {
      subject: 'SEC Filing Digest - No New Filings',
      body: '<p>No new filings from tracked A&D companies today.</p>'
    }
  }];
}

let html = '<h2>SEC Filing Digest - ' + new Date().toLocaleDateString() + '</h2>';

for (const item of items) {
  const d = item.json;
  const color =
    d.sentiment === 'positive' ? '#2e7d32' :
    d.sentiment === 'negative' ? '#c62828' :
    d.sentiment === 'mixed' ? '#ef6c00' : '#616161';

  html += '<div style="border-left:4px solid ' + color + ';padding:12px;margin:16px 0;">';
  html += '<h3>' + d.company_name + ' (' + d.ticker + ') - ' + d.form_type + '</h3>';
  html += '<p><strong>Filed:</strong> ' + d.filing_date + ' | ';
  html += '<strong>Sentiment:</strong> <span style="color:' + color + '">' + d.sentiment + '</span></p>';
  html += '<p>' + (d.summary || '') + '</p>';
  if (d.financial_highlights) html += '<p><strong>Financials:</strong> ' + d.financial_highlights + '</p>';
  if (d.key_risks) html += '<p><strong>Risks:</strong> ' + d.key_risks + '</p>';
  if (d.contracts_mentioned) html += '<p><strong>Contracts:</strong> ' + d.contracts_mentioned + '</p>';
  if (d.filing_url) html += '<p><a href="' + d.filing_url + '">View Filing</a></p>';
  html += '</div>';
}

return [{
  json: {
    subject: 'SEC Filing Digest - ' + items.length + ' filing(s) - ' + new Date().toLocaleDateString(),
    body: html
  }
}];
